  # Renders a single Heroicon as an inline SVG.
  #
  # @param name [Symbol] key into {ICON_PATHS}
  # @param options [Hash] HTML attributes; `:class` merges with the default sizing class
  # @return [ActiveSupport::SafeBuffer]
  # @raise [KeyError] if `name` is not registered in {ICON_PATHS}
  def heroicon(name, options = {})
    body = ICON_PATHS.fetch(name)
    css = options.delete(:class) || "h-4 w-4"
    content_tag(:svg,
      body.html_safe,
      xmlns: "http://www.w3.org/2000/svg",
      viewBox: "0 0 24 24",
      fill: "none",
      stroke: "currentColor",
      "stroke-width": "1.75",
      "stroke-linecap": "round",
      "stroke-linejoin": "round",
      class: "inline-block shrink-0 #{css}",
      "aria-hidden": "true",
      focusable: "false"
    )
  end
end
